#!/usr/bin/env node
/**
 * Backfill / regenerate the photo-realistic Printful listing mockup for every
 * published product whose `mockup_url` is missing, equal to the bare design
 * URL (publish-time fallback), or otherwise auto-generated by Printful.
 * Creator-uploaded custom listing photos (Supabase Storage) are skipped so
 * we never clobber a manual upload.
 *
 * Usage:
 *   node scripts/printful-refresh-listing-mockups.mjs           # all auto/missing
 *   node scripts/printful-refresh-listing-mockups.mjs --force   # also redo Printful CDN URLs
 *   node scripts/printful-refresh-listing-mockups.mjs <id> ...  # only specific product ids
 *
 * This wrapper loads `.env.local` into `process.env` and then spawns `tsx`
 * against `printful-refresh-listing-mockups.mts`, where the real logic lives.
 */

import { spawnSync } from "node:child_process";
import { existsSync, promises as fs } from "node:fs";
import { fileURLToPath } from "node:url";
import path from "node:path";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const ROOT = path.resolve(__dirname, "..");

/** Tiny dotenv loader — avoids adding a runtime dep just for one script. */
async function loadEnvLocal() {
  const file = path.join(ROOT, ".env.local");
  try {
    const raw = await fs.readFile(file, "utf8");
    for (const line of raw.split(/\r?\n/)) {
      const m = line.match(/^\s*([A-Z0-9_]+)\s*=\s*(.*)\s*$/);
      if (!m) continue;
      const [, k, vRaw] = m;
      if (process.env[k] != null) continue;
      let v = vRaw;
      if ((v.startsWith('"') && v.endsWith('"')) || (v.startsWith("'") && v.endsWith("'"))) {
        v = v.slice(1, -1);
      }
      process.env[k] = v;
    }
  } catch {
    // ok — .env.local optional (env may come from the shell)
  }
}

await loadEnvLocal();

const tsxBin = path.join(ROOT, "node_modules", ".bin", "tsx");
if (!existsSync(tsxBin)) {
  console.error(
    "[printful-refresh-listing-mockups] `tsx` is not installed.\n" +
      "Install once with: pnpm add -D tsx\n" +
      "Then re-run this script.",
  );
  process.exit(2);
}

const runnerTs = path.join(__dirname, "printful-refresh-listing-mockups.mts");
const passthroughArgs = process.argv.slice(2);

const res = spawnSync(tsxBin, [runnerTs, ...passthroughArgs], {
  cwd: ROOT,
  stdio: "inherit",
  env: { ...process.env, NODE_NO_WARNINGS: "1" },
});

process.exit(res.status ?? 1);
